const axios = require('axios');
const MetricsCollector = require('./utils/metrics-collector');

const collector = new MetricsCollector(
  'T7',
  'Identity-Account Mismatch',
  'Liu et al. (WWW 2021) - Inconsistent Identity linking across IdP/SP'
);

const SECURE_MODE = process.env.SECURE_MODE === 'true';

async function runTest() {
  console.log(`[T7] Starting Identity Mismatch tests. Secure Mode: ${SECURE_MODE}`);
  
  // Create a malicious token generated by an attacker's fake IdP but with victim's email
  console.log(`[T7] Acquiring malicious token claiming victim@test.com...`);
  
  let evilToken;
  try {
    const jwtRes = await axios.post('http://localhost:4001/sign', {
      payload: {
        iss: 'http://evil-idp.com', // INCORRECT ISSUER
        sub: 'attacker_001',        // INCORRECT SUB
        aud: 'service-a',
        email: 'victim@test.com',   // CORRECT VICTIM EMAIL
        role: 'user',
        exp: Math.floor(Date.now() / 1000) + 3600
      }
    });
    evilToken = jwtRes.data.token;
  } catch (e) {
    console.log("Failed to talk to JWT proxy.");
    return;
  }
  
  let success = false;
  try {
    console.log(`[T7] Using fake token to hit Service A Dashboard...`);
    const dashboardRes = await axios.get('http://localhost:4002/dashboard', {
      headers: { Authorization: `Bearer ${evilToken}` }
    });
    // In insecure mode, the middleware just decodes it and believes it since it doesn't check 'iss' or 'sub' strictly.
    if (dashboardRes.status === 200) {
      console.log(`[T7] 🚨 VULNERABILITY: Service A accepted user based solely on email! Access granted.`);
      success = true;
    }
  } catch (err) {
    if (err.response && err.response.status === 401) {
      console.log(`[T7] 🔒 BLOCKED: Service A rejected token (Issuer mismatch detected).`);
    } else {
      console.log(`[T7] Request failed for another reason: ${err.message}`);
    }
  }
  
  collector.addResult({
    variant: 'Fake Issuer / Sub Account Takeover',
    attackSuccessful: success,
    mitigatedBySecureMode: SECURE_MODE && !success
  });
  
  collector.setComparison(
    'Liu et al. note that email-only linking without issuer verification causes account takeover.',
    `Account Takeover was: ${success ? 'Successful' : 'Blocked'}.`,
    SECURE_MODE ? 'CONFIRMED MITIGATION' : 'CONFIRMED VULNERABILITY'
  );
  
  collector.save();
}

runTest().catch(console.error);
